// Inject common components
function initCommon(activePage) {
  // Scroll reveal
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => { if (entry.isIntersecting) entry.target.classList.add('visible'); });
  }, { threshold: 0.1 });
  document.querySelectorAll('.fade-up').forEach(el => observer.observe(el));

  // Nav scroll
  window.addEventListener('scroll', () => {
    const nav = document.getElementById('nav');
    const cta = document.getElementById('floatingCta');
    if (nav) nav.classList.toggle('scrolled', window.scrollY > 10);
    if (cta) { if (window.scrollY > 400) cta.classList.add('show'); else cta.classList.remove('show'); }
  });

  // Banner close
  const bannerClose = document.querySelector('.top-banner-close');
  if (bannerClose) {
    bannerClose.addEventListener('click', () => {
      document.getElementById('topBanner').style.display = 'none';
      document.documentElement.style.setProperty('--banner-h', '0px');
    });
  }

  // Dark mode — system preference only (no manual toggle)
  if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
    document.documentElement.classList.add('dark');
  }
  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
    document.documentElement.classList.toggle('dark', e.matches);
  });
  initCustomSelects();

  // Active nav link
  if (activePage) {
    document.querySelectorAll('.nav-links a').forEach(a => {
      if (a.dataset.page === activePage) a.classList.add('active');
    });
  }
}

