function initExitPopup() {
  if (window.__exitPopupShown) return;
  const overlay = document.getElementById('exitOverlay');
  if (!overlay) return;

  function showPopup() {
    if (window.__exitPopupShown) return;
    window.__exitPopupShown = true;
    overlay.classList.add('show');
  }

  function hidePopup() {
    overlay.classList.remove('show');
  }

  // 메인 진입 후 3초 뒤 표시
  setTimeout(showPopup, 3000);

  document.getElementById('exitClose').addEventListener('click', hidePopup);
  document.getElementById('exitSkip').addEventListener('click', hidePopup);
  overlay.addEventListener('click', (e) => { if (e.target === overlay) hidePopup(); });
}

function initCustomSelects() {
  document.querySelectorAll('select.form-select').forEach(select => {
    const wrapper = document.createElement('div');
    wrapper.className = 'custom-select';

    const options = Array.from(select.options);
    const placeholder = options[0]?.text || '선택하세요';

    // Trigger button
    const trigger = document.createElement('div');
    trigger.className = 'custom-select-trigger';
    trigger.innerHTML = `<span>${placeholder}</span><svg class="chevron" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M4 6l4 4 4-4"/></svg>`;

    // Dropdown list
    const dropdown = document.createElement('div');
    dropdown.className = 'custom-select-dropdown';

    options.forEach((opt, i) => {
      if (i === 0) return; // skip placeholder
      const item = document.createElement('div');
      item.className = 'custom-select-option';
      item.dataset.value = opt.value || opt.text;
      item.innerHTML = `<svg class="option-icon" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><path d="M8 4v8M4 8h8"/></svg><span>${opt.text}</span>`;
      item.addEventListener('click', () => {
        select.value = opt.value || opt.text;
        select.dispatchEvent(new Event('change', { bubbles: true }));
        trigger.querySelector('span').textContent = opt.text;
        trigger.classList.add('filled');
        dropdown.querySelectorAll('.custom-select-option').forEach(o => o.classList.remove('selected'));
        item.classList.add('selected');
        wrapper.classList.remove('open');
      });
      dropdown.appendChild(item);
    });

    // Toggle open/close
    trigger.addEventListener('click', (e) => {
      e.stopPropagation();
      document.querySelectorAll('.custom-select.open').forEach(s => { if (s !== wrapper) s.classList.remove('open'); });
      wrapper.classList.toggle('open');
    });

    // Close on outside click
    document.addEventListener('click', () => wrapper.classList.remove('open'));

    // Hide original select
    select.style.display = 'none';
    select.parentNode.insertBefore(wrapper, select);
    wrapper.appendChild(trigger);
    wrapper.appendChild(dropdown);
    wrapper.appendChild(select);
  });
}

