//   - consulting : 지원사업 컨설팅 신청 (자가진단 결과 외부 share URL 별도)
//   - calendar   : LM1 — 하반기 지원사업 캘린더 PDF / 캘린더 미팅 예약
//   - diagnosis  : (deprecated 2026-04-29) HubSpot에서 폼 삭제됨. 호출 차단.
const HUBSPOT_PORTAL_ID = '244341313';
const HUBSPOT_REGION = 'na2';
const HUBSPOT_FORMS = {
  contact:    'b8dff54f-8dea-4d44-a228-b4caf67cc53d',
  demo:       'f786d94e-ce68-43e4-85f2-d4b2c631f948',
  consulting: 'ec6721d7-de63-4ced-8c00-4d7be887d8cb',
  calendar:   '02e5985f-ab91-4e1d-8dfc-29fa510aee8d',
  diagnosis:  null,  /* deprecated · 2026-04-29 — HubSpot에서 폼 삭제됨 */
};

// @deprecated 2026-04-29 — 메인 5폼은 hbspt.forms.create (forms-embed v2) 로 전환됨.
// Forms v3 Non-HubSpot Forms API 는 form analytics 만 기록하고 contact 생성은 form별
// "Always create contact" 설정에 의존하는데 우리 폼들이 OFF 상태였기 때문에 contact 0건 적재 사고 발생.
// 이 함수는 solutions-subsidy-check.html consulting-inline 등 일부 잔여 호출처와의
// 컴파일 타임 컨플릭트 방지를 위해 보존만 함. 신규 호출 금지.
function submitToHubSpot(formId, fields, redirectUrl, onError) {
  const url = `https://api.hsforms.com/submissions/v3/integration/submit/${HUBSPOT_PORTAL_ID}/${formId}`;
  const data = {
    fields: fields,
    context: {
      pageUri: window.location.href,
      pageName: document.title,
    },
  };

  const handleFail = (err) => {
    console.error('HubSpot submit failed:', err);
    if (typeof onError === 'function') {
      onError(err);
    } else {
      alert('제출 중 오류가 발생했습니다. 잠시 후 다시 시도해주시거나 help@futureworklab.co.kr 로 연락 부탁드립니다.');
    }
    return { ok: false, error: err };
  };

  return fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  })
    .then(res => {
      if (res.ok) {
        if (redirectUrl) window.location.href = redirectUrl;
        return { ok: true };
      }
      return res.json().then(handleFail).catch(handleFail);
    })
    .catch(handleFail);
}

